allow:
Bash(powershell.exe -Command "
\\$json = @{
  'allow-direct-routing' = \\$true
  'builder' = @{
    'gc' = @{
      'defaultKeepStorage' = '20GB'
      'enabled' = \\$true
    }
  }
  'containerd' = '/run/containerd/containerd.sock'
  'default-network-opts' = @{
    'bridge' = @{
      'com.docker.network.enable_ipv4' = 'true'
      'com.docker.network.enable_ipv6' = 'false'
    }
  }
  'experimental' = \\$false
  'features' = @{
    'cdi' = \\$true
    'containerd-snapshotter' = \\$true
  }
  'host-gateway-ips' = @\('192.168.65.254', 'fdc4:f303:9324::254'\)
  'hosts' = @\('fd://'\)
  'insecure-registries' = @\('hubproxy.docker.internal:5555'\)
  'ipv6' = \\$false
  'log-format' = 'json'
  'mtu' = 1500
  'pidfile' = '/run/desktop/docker.pid'
  'proxies' = @{}
  'runtimes' = @{
    'nvidia' = @{
      'path' = 'nvidia-container-runtime'
    }
  }
  'shutdown-timeout' = 2
  'storage-driver' = 'overlayfs'
  'swarm-default-advertise-addr' = '192.168.65.3'
  'userland-proxy' = \\$false
}
\\$jsonStr = \\$json | ConvertTo-Json -Depth 10
Write-Host \\$jsonStr
\\$jsonStr | wsl -d docker-desktop -- sh -c 'cat > /tmp/docker-desktop-root/run/config/docker/daemon.json'
Write-Host 'Written'
" 2>&1)
